$ErrorActionPreference = "Stop"

$project = "C:\Users\arauj\grafica-flash"
$file = Join-Path $project "lib\current-company-client.ts"

if (!(Test-Path -LiteralPath $project)) {
  Write-Host "Projeto nao encontrado em $project" -ForegroundColor Red
  exit 1
}

if (Test-Path -LiteralPath $file) {
  $backup = $file + ".backup-bearer-token-" + (Get-Date -Format "yyyyMMddHHmmss")
  Copy-Item -LiteralPath $file -Destination $backup -Force
  Write-Host "Backup criado: $backup" -ForegroundColor DarkYellow
}

$base64 = @"

"@

$bytes = [System.Convert]::FromBase64String($base64.Trim())
$content = [System.Text.Encoding]::UTF8.GetString($bytes)
$utf8NoBom = New-Object System.Text.UTF8Encoding($false)
[System.IO.File]::WriteAllText($file, $content, $utf8NoBom)

Remove-Item -Recurse -Force (Join-Path $project ".next") -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "Bearer token corrigido em lib/current-company-client.ts." -ForegroundColor Green
Write-Host "Agora rode: npm run build" -ForegroundColor Yellow
